#include <iostream>\n#include <vector>\n#include <set>\n#include <cstdint>\n#include <limits>\n\n// aaaaaa\n\nclass Graph {\n public:\n  Graph(const std::vector<std::vector<int>>& matrix, int a, int b) {\n    Build(matrix, a, b);\n  }\n\n  int64_t GetDist() {\n    return answer_;\n  }\n\n private:\n  void Build(const std::vector<std::vector<int>>& matrix, int a, int b) {\n    a--;\n    b--;\n    if (a == b) {\n      answer_ = 0;\n      return;\n    }\n    int n = static_cast<int>(matrix.size());\n    std::vector<int64_t> dist(n, kInf);\n    dist[a] = 0;\n    std::set<std::pair<int, int64_t>, PairCompare> q;\n    q.emplace(a, 0);\n    while (!q.empty()) {\n      int v = q.begin()->first;\n      int64_t d = q.begin()->second;\n      q.erase(q.begin());\n      if (d > dist[v]) {\n        continue;\n      }\n      // for (const std::pair<int, int>& child : table_[v]) {\n      for (int j = 0; j < n; j++) {\n        if (v == j || matrix[v][j] == -1) {\n          continue;\n        }\n        int ch_v = j;\n        int ch_w = matrix[v][j];\n        int64_t new_dist = dist[v] + ch_w;\n        if (new_dist < dist[ch_v]) {\n          dist[ch_v] = new_dist;\n          q.emplace(ch_v, new_dist);\n        }\n      }\n    }\n    if (dist[b] != kInf) {\n      answer_ = dist[b];\n    }\n  }\n\n  struct PairCompare {\n    bool operator()(const std::pair<int, int64_t>& l, const std::pair<int, int64_t>& r) const {\n      return l.second < r.second;\n    }\n  };\n\n  int64_t answer_ = -1;\n  static constexpr int64_t kInf = std::numeric_limits<int64_t>::max();\n};\n\nint main() {\n\n  // magic words\n  std::ios_base::sync_with_stdio(false);\n  std::cin.tie(nullptr);\n  std::cout.tie(nullptr);\n\n  int n = 0;\n  int a = 0;\n  int b = 0;\n  std::cin >> n >> a >> b;\n\n  std::vector<std::vector<int>> matrix(n, std::vector<int>(n));\n  for (int i = 0; i < n; i++) {\n    for (int j = 0; j < n; j++) {\n      std::cin >> matrix[i][j];\n    }\n  }\n\n  Graph g(matrix, a, b);\n\n  std::cout << g.GetDist();\n  return 0;\n}